from django.shortcuts import render, redirect, get_object_or_404
from django.views import View
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.utils.decorators import method_decorator
from django.core.mail import send_mail
from django.conf import settings
from datetime import date
from decimal import Decimal
from catalog.models import Barco
from cart.services import get_cart, clear_cart
from .models import Reserva, HistorialEstadoReserva
from .forms import ReservationStep1Form, ReservationStep2Form, ReservationStep3Form, TrackReservationForm


class ReservationStep1View(View):
    def get(self, request):
        form = ReservationStep1Form()
        cart = get_cart(request)
        barcos_en_cesta = []

        for barco_id_str, item in cart.items():
            try:
                barco = Barco.objects.get(id=int(barco_id_str))
                barcos_en_cesta.append(barco)
            except Barco.DoesNotExist:
                pass

        if not barcos_en_cesta:
            messages.warning(request, 'Tu cesta está vacía. Añade barcos antes de reservar.')
            return redirect('catalog:barco_list')

        context = {
            'form': form,
            'barcos_en_cesta': barcos_en_cesta,
        }
        return render(request, 'reservations/step1.html', context)

    def post(self, request):
        form = ReservationStep1Form(request.POST)
        if form.is_valid():
            request.session['reserva_fecha_inicio'] = str(form.cleaned_data['fecha_inicio'])
            request.session['reserva_fecha_fin'] = str(form.cleaned_data['fecha_fin'])
            request.session.modified = True
            return redirect('reservations:step2')

        cart = get_cart(request)
        barcos_en_cesta = []
        for barco_id_str, item in cart.items():
            try:
                barco = Barco.objects.get(id=int(barco_id_str))
                barcos_en_cesta.append(barco)
            except Barco.DoesNotExist:
                pass

        context = {
            'form': form,
            'barcos_en_cesta': barcos_en_cesta,
        }
        return render(request, 'reservations/step1.html', context)


class ReservationStep2View(View):
    def get(self, request):
        if 'reserva_fecha_inicio' not in request.session:
            messages.warning(request, 'Por favor, completa el paso 1 primero.')
            return redirect('reservations:step1')

        form = ReservationStep2Form()

        if request.user.is_authenticated:
            form.fields['nombre_cliente'].initial = request.user.get_full_name() or request.user.username
            form.fields['email_cliente'].initial = request.user.email

        context = {'form': form}
        return render(request, 'reservations/step2.html', context)

    def post(self, request):
        if 'reserva_fecha_inicio' not in request.session:
            messages.warning(request, 'Por favor, completa el paso 1 primero.')
            return redirect('reservations:step1')

        form = ReservationStep2Form(request.POST)
        if form.is_valid():
            request.session['reserva_nombre_cliente'] = form.cleaned_data['nombre_cliente']
            request.session['reserva_email_cliente'] = form.cleaned_data['email_cliente']
            request.session['reserva_telefono_cliente'] = form.cleaned_data['telefono_cliente']
            request.session.modified = True
            return redirect('reservations:step3')

        context = {'form': form}
        return render(request, 'reservations/step2.html', context)


class ReservationStep3View(View):
    def get(self, request):
        if 'reserva_fecha_inicio' not in request.session or 'reserva_nombre_cliente' not in request.session:
            messages.warning(request, 'Por favor, completa los pasos anteriores primero.')
            return redirect('reservations:step1')

        cart = get_cart(request)
        if not cart:
            messages.warning(request, 'Tu cesta está vacía.')
            return redirect('catalog:barco_list')

        fecha_inicio = request.session.get('reserva_fecha_inicio')
        fecha_fin = request.session.get('reserva_fecha_fin')

        barcos_info = []
        total_sin_combustible = Decimal('0')
        total_combustible = Decimal('0')

        for barco_id_str, item in cart.items():
            try:
                barco = Barco.objects.get(id=int(barco_id_str))
                cantidad = item['cantidad']

                fecha_inicio_obj = __import__('datetime').datetime.strptime(fecha_inicio, '%Y-%m-%d').date()
                fecha_fin_obj = __import__('datetime').datetime.strptime(fecha_fin, '%Y-%m-%d').date()
                dias = (fecha_fin_obj - fecha_inicio_obj).days

                subtotal = barco.precio_dia * cantidad * dias
                total_sin_combustible += subtotal

                tasa_combustible = Decimal('0')
                if barco.categoria.nombre.lower() != 'velero':
                    tasa_combustible = Decimal('50') * cantidad * dias

                total_combustible += tasa_combustible

                barcos_info.append({
                    'barco': barco,
                    'cantidad': cantidad,
                    'dias': dias,
                    'subtotal': subtotal,
                    'tasa_combustible': tasa_combustible,
                })
            except Barco.DoesNotExist:
                pass

        total = total_sin_combustible + total_combustible

        form = ReservationStep3Form()
        context = {
            'form': form,
            'barcos_info': barcos_info,
            'fecha_inicio': fecha_inicio,
            'fecha_fin': fecha_fin,
            'total_sin_combustible': total_sin_combustible,
            'total_combustible': total_combustible,
            'total': total,
        }
        return render(request, 'reservations/step3.html', context)

    def post(self, request):
        if 'reserva_fecha_inicio' not in request.session or 'reserva_nombre_cliente' not in request.session:
            messages.warning(request, 'Por favor, completa los pasos anteriores primero.')
            return redirect('reservations:step1')

        form = ReservationStep3Form(request.POST)
        if form.is_valid():
            cart = get_cart(request)
            metodo_pago = form.cleaned_data['metodo_pago']

            fecha_inicio = request.session.get('reserva_fecha_inicio')
            fecha_fin = request.session.get('reserva_fecha_fin')
            nombre_cliente = request.session.get('reserva_nombre_cliente')
            email_cliente = request.session.get('reserva_email_cliente')
            telefono_cliente = request.session.get('reserva_telefono_cliente', '')

            fecha_inicio_obj = __import__('datetime').datetime.strptime(fecha_inicio, '%Y-%m-%d').date()
            fecha_fin_obj = __import__('datetime').datetime.strptime(fecha_fin, '%Y-%m-%d').date()

            for barco_id_str, item in cart.items():
                try:
                    barco = Barco.objects.get(id=int(barco_id_str))
                    cantidad = item['cantidad']
                    dias = (fecha_fin_obj - fecha_inicio_obj).days

                    precio_dia = barco.precio_dia
                    tasa_combustible_dia = Decimal('0')
                    if barco.categoria.nombre.lower() != 'velero':
                        tasa_combustible_dia = Decimal('50')

                    importe_total = (precio_dia + tasa_combustible_dia) * cantidad * dias

                    estado_inicial = 'PAGADO' if metodo_pago == 'paypal' else 'PENDIENTE_DE_PAGO'

                    reserva = Reserva.objects.create(
                        cliente=request.user if request.user.is_authenticated else None,
                        nombre_cliente=nombre_cliente,
                        email_cliente=email_cliente,
                        telefono_cliente=telefono_cliente,
                        barco=barco,
                        cantidad=cantidad,
                        fecha_inicio=fecha_inicio_obj,
                        fecha_fin=fecha_fin_obj,
                        precio_dia=precio_dia,
                        tasa_combustible_dia=tasa_combustible_dia,
                        importe_total=importe_total,
                        estado=estado_inicial,
                        metodo_pago=metodo_pago,
                    )

                    HistorialEstadoReserva.objects.create(
                        reserva=reserva,
                        estado_anterior='CREADA',
                        estado_nuevo=estado_inicial,
                        usuario=request.user if request.user.is_authenticated else None,
                        notas='Reserva creada en el sistema'
                    )

                    asunto = f'Confirmación de Reserva - Código: {reserva.codigo_seguimiento}'
                    mensaje = f'''Hola {nombre_cliente},

Tu reserva ha sido confirmada exitosamente.

Detalles de la Reserva:
- Código de Seguimiento: {reserva.codigo_seguimiento}
- Barco: {barco.nombre}
- Fecha de Inicio: {fecha_inicio}
- Fecha de Fin: {fecha_fin}
- Importe Total: {importe_total}€
- Método de Pago: {metodo_pago}
- Estado: {estado_inicial}

Puedes consultar el estado de tu reserva en: {request.build_absolute_uri('/reserva/seguimiento/')}

Gracias por confiar en Hundidos.
'''

                    try:
                        send_mail(
                            asunto,
                            mensaje,
                            settings.DEFAULT_FROM_EMAIL,
                            [email_cliente],
                            fail_silently=True,
                        )
                    except:
                        pass

                    request.session['ultima_reserva_codigo'] = reserva.codigo_seguimiento
                    request.session.modified = True

                except Barco.DoesNotExist:
                    pass

            clear_cart(request)
            for key in list(request.session.keys()):
                if key.startswith('reserva_'):
                    del request.session[key]
            request.session.modified = True

            return redirect('reservations:confirmation')

        context = {'form': form}
        return render(request, 'reservations/step3.html', context)


class ReservationConfirmationView(View):
    def get(self, request):
        codigo = request.session.get('ultima_reserva_codigo')
        if not codigo:
            messages.warning(request, 'No hay reserva para confirmar.')
            return redirect('/')

        try:
            reserva = Reserva.objects.get(codigo_seguimiento=codigo)
        except Reserva.DoesNotExist:
            messages.error(request, 'Reserva no encontrada.')
            return redirect('/')

        context = {'reserva': reserva}
        return render(request, 'reservations/confirmation.html', context)


class TrackReservationView(View):
    def get(self, request):
        form = TrackReservationForm()
        context = {'form': form}
        return render(request, 'reservations/track.html', context)

    def post(self, request):
        form = TrackReservationForm(request.POST)
        if form.is_valid():
            codigo = form.cleaned_data['codigo_seguimiento']
            return redirect('reservations:track_detail', codigo=codigo)

        context = {'form': form}
        return render(request, 'reservations/track.html', context)


class TrackReservationDetailView(View):
    def get(self, request, codigo):
        try:
            reserva = Reserva.objects.get(codigo_seguimiento=codigo)
        except Reserva.DoesNotExist:
            messages.error(request, 'Reserva no encontrada.')
            return redirect('reservations:track')

        historial = HistorialEstadoReserva.objects.filter(reserva=reserva).order_by('-fecha_cambio')

        context = {
            'reserva': reserva,
            'historial': historial,
        }
        return render(request, 'reservations/track_detail.html', context)


class CancelReservationView(View):
    def post(self, request, codigo):
        try:
            reserva = Reserva.objects.get(codigo_seguimiento=codigo)
        except Reserva.DoesNotExist:
            messages.error(request, 'Reserva no encontrada.')
            return redirect('reservations:track')

        if reserva.estado == 'DEVUELTO':
            messages.error(request, 'No se puede cancelar una reserva ya devuelta.')
            return redirect('reservations:track_detail', codigo=codigo)

        estado_anterior = reserva.estado
        reserva.estado = 'CANCELADA'
        reserva.save()

        HistorialEstadoReserva.objects.create(
            reserva=reserva,
            estado_anterior=estado_anterior,
            estado_nuevo='CANCELADA',
            usuario=request.user if request.user.is_authenticated else None,
            notas='Reserva cancelada por el cliente'
        )

        messages.success(request, 'Reserva cancelada exitosamente.')
        return redirect('reservations:track_detail', codigo=codigo)


@method_decorator(login_required, name='dispatch')
class MyReservationsView(View):
    def get(self, request):
        reservas = Reserva.objects.filter(cliente=request.user).order_by('-created_at')
        context = {'reservas': reservas}
        return render(request, 'reservations/my_reservations.html', context)


@method_decorator(login_required, name='dispatch')
class MyReservationDetailView(View):
    def get(self, request, id):
        reserva = get_object_or_404(Reserva, id=id, cliente=request.user)
        historial = HistorialEstadoReserva.objects.filter(reserva=reserva).order_by('-fecha_cambio')
        context = {
            'reserva': reserva,
            'historial': historial,
        }
        return render(request, 'reservations/my_reservation_detail.html', context)


class PayPalReturnView(View):
    def get(self, request):
        messages.success(request, 'Pago completado exitosamente.')
        return redirect('reservations:confirmation')


class PayPalCancelView(View):
    def get(self, request):
        messages.warning(request, 'Pago cancelado. Por favor, intenta de nuevo.')
        return redirect('reservations:step3')

