{% block content %}
<div class="container">
    <div class="step-indicator">
        <div class="step active">1. Fechas</div>
        <div class="step">2. Datos</div>
        <div class="step">3. Pago</div>
    </div>

    <div class="reservation-container">
        <div class="reservation-form">
            <h2>Paso 1: Selecciona las Fechas</h2>

            <form method="post">
                {% csrf_token %}

                <div class="form-group">
                    {{ form.fecha_inicio.label_tag }}
                    {{ form.fecha_inicio }}
                    {% if form.fecha_inicio.errors %}
                        <ul class="errorlist">
                            {% for error in form.fecha_inicio.errors %}
                                <li>{{ error }}</li>
                            {% endfor %}
                        </ul>
                    {% endif %}
                </div>

                <div class="form-group">
                    {{ form.fecha_fin.label_tag }}
                    {{ form.fecha_fin }}
                    {% if form.fecha_fin.errors %}
                        <ul class="errorlist">
                            {% for error in form.fecha_fin.errors %}
                                <li>{{ error }}</li>
                            {% endfor %}
                        </ul>
                    {% endif %}
                </div>

                {% if form.non_field_errors %}
                    <div style="color: #dc3545; margin-bottom: 20px;">
                        {% for error in form.non_field_errors %}
                            <p>{{ error }}</p>
                        {% endfor %}
                    </div>
